import { Dialog as ArkSheet } from "@ark-ui/react/dialog";
import { FiX } from "react-icons/fi";
import { tv } from "tailwind-variants";

import { cn } from "@/lib/utils";

import type { ComponentProps } from "react";

const ArkSheetVariants = tv({
  slots: {
    trigger: "",
    backdrop:
      "fixed z-50 flex flex-col gap-4 bg-background shadow-lg transition ease-in-out data-[state=closed]:animate-out data-[state=open]:animate-in data-[state=closed]:duration-300 data-[state=open]:duration-500",
    positioner: "fixed inset-0 z-50 flex items-center justify-center",
    content:
      "data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 data-[state=closed]:slide-out-to-top-[2%] data-[state=open]:slide-in-from-top-[2%] relative grid w-full max-w-lg gap-4 border bg-background p-6 shadow-lg duration-200 data-[state=closed]:animate-out data-[state=open]:animate-in sm:rounded-lg",
    title: "font-semibold text-lg leading-none tracking-tight",
    description: "text-muted-foreground text-sm",
    closeTrigger:
      "absolute top-4 right-4 rounded-sm opacity-70 ring-offset-background transition-opacity hover:opacity-100 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:pointer-events-none",
  },
});

const {
  trigger,
  backdrop,
  positioner,
  content,
  title,
  description,
  closeTrigger,
} = ArkSheetVariants();

const ArkSheetProvider = ArkSheet.RootProvider;
const ArkSheetContext = ArkSheet.Context;
const ArkSheetRoot = ArkSheet.Root;

const ArkSheetTrigger = ({
  className,
  ...rest
}: ComponentProps<typeof ArkSheet.Trigger>) => (
  <ArkSheet.Trigger className={cn(trigger(), className)} {...rest} />
);

const ArkSheetBackdrop = ({
  className,
  ...rest
}: ComponentProps<typeof ArkSheet.Backdrop>) => (
  <ArkSheet.Backdrop className={cn(backdrop(), className)} {...rest} />
);

const ArkSheetPositioner = ({
  className,
  ...rest
}: ComponentProps<typeof ArkSheet.Positioner>) => (
  <ArkSheet.Positioner className={cn(positioner(), className)} {...rest} />
);

interface ArkSheetContentProps extends ComponentProps<typeof ArkSheet.Content> {
  side?: "top" | "right" | "bottom" | "left";
}

const ArkSheetContent = ({
  className,
  side = "right",
  ...rest
}: ArkSheetContentProps) => (
  <ArkSheet.Content
    className={cn(
      content(),
      side === "right" &&
        "data-[state=closed]:slide-out-to-right data-[state=open]:slide-in-from-right inset-y-0 right-0 h-full w-3/4 border-l sm:max-w-sm",
      side === "left" &&
        "data-[state=closed]:slide-out-to-left data-[state=open]:slide-in-from-left inset-y-0 left-0 h-full w-3/4 border-r sm:max-w-sm",
      side === "top" &&
        "data-[state=closed]:slide-out-to-top data-[state=open]:slide-in-from-top inset-x-0 top-0 h-auto border-b",
      side === "bottom" &&
        "data-[state=closed]:slide-out-to-bottom data-[state=open]:slide-in-from-bottom inset-x-0 bottom-0 h-auto border-t",
      className,
    )}
    {...rest}
  />
);

const ArkSheetTitle = ({
  className,
  ...rest
}: ComponentProps<typeof ArkSheet.Title>) => (
  <ArkSheet.Title className={cn(title(), className)} {...rest} />
);

const ArkSheetDescription = ({
  className,
  ...rest
}: ComponentProps<typeof ArkSheet.Description>) => (
  <ArkSheet.Description className={cn(description(), className)} {...rest} />
);

const ArkSheetCloseTrigger = ({
  className,
  children,
  asChild,
  ...rest
}: ComponentProps<typeof ArkSheet.CloseTrigger>) => {
  // If there are no children, render the default X icon
  if (!children) {
    return (
      <ArkSheet.CloseTrigger
        className={cn(closeTrigger(), className)}
        {...rest}
      >
        <FiX className="h-4 w-4" />
        <span className="sr-only">Close</span>
      </ArkSheet.CloseTrigger>
    );
  }

  // If children are provided, use them inside the CloseTrigger
  // This is useful for creating buttons that close the ArkSheet
  return (
    <ArkSheet.CloseTrigger
      className={cn(className)}
      asChild={asChild}
      {...rest}
    >
      {children}
    </ArkSheet.CloseTrigger>
  );
};

export {
  ArkSheetRoot,
  ArkSheetTrigger,
  ArkSheetBackdrop,
  ArkSheetPositioner,
  ArkSheetContent,
  ArkSheetTitle,
  ArkSheetDescription,
  ArkSheetCloseTrigger,
  ArkSheetProvider,
  ArkSheetContext,
};

import { clsx } from "clsx";
import { twMerge } from "tailwind-merge";

import type { ClassValue } from "clsx";

export const cn = (...inputs: ClassValue[]) => {
  return twMerge(clsx(inputs));
};
